const FEES = { "0-100": 2.99, "101-500": 4.99, "501-1000": 7.99, "1001+": 9.99 };

function getFee(amount) {
  if (amount <= 100) return FEES["0-100"];
  if (amount <= 500) return FEES["101-500"];
  if (amount <= 1000) return FEES["501-1000"];
  return FEES["1001+"];
}

