function AuthScreen({ onAuth }) {
  const [tab, setTab] = useState("login");
  const [showPwd, setShowPwd] = useState(false);
  const [form, setForm] = useState({ email: "", password: "", name: "", phone: "" });
  const [loading, setLoading] = useState(false);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const submit = () => {
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      onAuth({ name: form.name || "Jean-Paul Mbeki", email: form.email || "jp@email.com", phone: "+33 6 12 34 56 78" });
    }, 1400);
  };

  return (
    <div className="auth-screen">
      <div className="auth-bg-circle" style={{ width: 300, height: 300, top: -80, right: -80 }} />
      <div className="auth-bg-circle" style={{ width: 180, height: 180, top: 120, left: -60 }} />
      <div className="auth-logo">
        <img src={`data:image/png;base64,${LOGO_FULL_B64}`} alt="Cash Money" style={{ height: 72, width: "auto", marginBottom: 12 }} />
        <p>Envoyez de l'argent partout en Afrique</p>
      </div>
      <div className="auth-card">
        <div className="tab-toggle">
          <button className={`tab-btn ${tab === "login" ? "active" : ""}`} onClick={() => setTab("login")}>Connexion</button>
          <button className={`tab-btn ${tab === "signup" ? "active" : ""}`} onClick={() => setTab("signup")}>Inscription</button>
        </div>

        {tab === "signup" && (
          <>
            <div className="input-group">
              <label className="input-label">Nom complet</label>
              <input className="input-field" placeholder="Jean-Paul Mbeki" value={form.name} onChange={e => set("name", e.target.value)} />
            </div>
            <div className="input-group">
              <label className="input-label">Téléphone</label>
              <input className="input-field" placeholder="+33 6 12 34 56 78" value={form.phone} onChange={e => set("phone", e.target.value)} />
            </div>
          </>
        )}

        <div className="input-group">
          <label className="input-label">Email</label>
          <input className="input-field" type="email" placeholder="votre@email.com" value={form.email} onChange={e => set("email", e.target.value)} />
        </div>

        <div className="input-group">
          <label className="input-label">Mot de passe</label>
          <input className="input-field" type={showPwd ? "text" : "password"} placeholder="••••••••" value={form.password} onChange={e => set("password", e.target.value)} style={{ paddingRight: 48 }} />
          <button className="input-suffix" onClick={() => setShowPwd(s => !s)}>
            <Icon name={showPwd ? "eyeOff" : "eye"} size={18} />
          </button>
        </div>

        {tab === "login" && (
          <div style={{ textAlign: "right", marginBottom: 20, marginTop: -8 }}>
            <span style={{ fontSize: 13, color: "var(--primary)", fontWeight: 600, cursor: "pointer" }}>Mot de passe oublié ?</span>
          </div>
        )}

        <button className="btn-primary" onClick={submit} disabled={loading}>
          {loading ? "Chargement…" : tab === "login" ? "Se connecter" : "Créer mon compte"}
        </button>

        {tab === "signup" && (
          <p style={{ textAlign: "center", fontSize: 12, color: "var(--text3)", marginTop: 16, lineHeight: 1.6 }}>
            En créant un compte, vous acceptez nos{" "}
            <span style={{ color: "var(--primary)", fontWeight: 600 }}>Conditions d'utilisation</span> et notre{" "}
            <span style={{ color: "var(--primary)", fontWeight: 600 }}>Politique de confidentialité</span>.
          </p>
        )}
      </div>
    </div>
  );
}

