// ─── SEND FLOW ────────────────────────────────────────────────────────────────

function SendScreen({ preselectedCountry, onBack, onSuccess }) {
  const [step, setStep] = useState(0);
  const [country, setCountry] = useState(preselectedCountry || null);
  const [operator, setOperator] = useState(null);
  const [phone, setPhone] = useState("");
  const [recipient, setRecipient] = useState("");
  const [amount, setAmount] = useState("0");

  const numPress = (v) => {
    if (v === "." && amount.includes(".")) return;
    if (v === "." && amount === "0") { setAmount("0."); return; }
    if (amount === "0" && v !== ".") { setAmount(v); return; }
    if (amount.includes(".") && amount.split(".")[1].length >= 2) return;
    setAmount(a => a + v);
  };
  const numDel = () => setAmount(a => a.length <= 1 ? "0" : a.slice(0, -1));

  const numAmt = parseFloat(amount) || 0;
  const fee = getFee(numAmt);
  const total = numAmt + fee;
  const received = country ? Math.round(numAmt * country.rate) : 0;

  const canNext = [
    country && operator,
    recipient && phone,
    numAmt >= 5,
    true,
  ];

  return (
    <div className="screen fade-in">
      <div className="topbar">
        <button className="topbar-back" onClick={step === 0 ? onBack : () => setStep(s => s - 1)}>
          <Icon name="arrowLeft" size={20} /> {step === 0 ? "Retour" : "Précédent"}
        </button>
        <div style={{ fontSize: 13, color: "var(--text3)" }}>Étape {step + 1}/4</div>
      </div>

      <div className="send-screen">
        <StepIndicator step={step} total={4} />

        {/* STEP 0 — PAYS & OPÉRATEUR */}
        {step === 0 && (
          <div className="fade-in">
            <div className="card">
              <div className="card-title">🌍 Pays de destination</div>
              <div className="country-scroll" style={{ flexWrap: "wrap", display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10 }}>
                {COUNTRIES.map(c => (
                  <div key={c.code}
                    className={`country-chip ${country?.code === c.code ? "selected" : ""}`}
                    onClick={() => { setCountry(c); setOperator(null); }}
                    style={{ minWidth: "unset" }}
                  >
                    <div className="country-chip-flag">{c.flag}</div>
                    <div className="country-chip-name" style={{ fontSize: 10 }}>{c.name.split(" ")[0]}</div>
                  </div>
                ))}
              </div>
            </div>
            {country && (
              <div className="card fade-in">
                <div className="card-title">📱 Opérateur</div>
                <div className="operator-grid">
                  {country.operators.map(op => (
                    <div key={op}
                      className={`operator-card ${operator === op ? "selected" : ""}`}
                      onClick={() => setOperator(op)}
                    >
                      <div className="op-logo" style={{ background: OPERATOR_COLORS[op]?.bg, color: "white" }}>
                        {OPERATOR_LOGOS[op]}
                      </div>
                      <div>
                        <div className="op-name">{op}</div>
                        <div style={{ fontSize: 10, color: "var(--text3)", marginTop: 2 }}>Mobile Money</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* STEP 1 — BÉNÉFICIAIRE */}
        {step === 1 && (
          <div className="fade-in">
            <div className="card">
              <div className="card-title">👤 Bénéficiaire</div>
              <div className="input-group">
                <label className="input-label">Nom complet</label>
                <input className="input-field" placeholder="Ex: Aminata Diallo" value={recipient} onChange={e => setRecipient(e.target.value)} />
              </div>
              <div className="input-group">
                <label className="input-label">Numéro {operator}</label>
                <input className="input-field" placeholder={country?.phonePrefix + " …"} value={phone} onChange={e => setPhone(e.target.value)} />
              </div>
              <div style={{ background: "var(--surface2)", borderRadius: 12, padding: "12px 14px", display: "flex", gap: 10, alignItems: "flex-start" }}>
                <Icon name="info" size={16} color="var(--primary)" />
                <span style={{ fontSize: 12, color: "var(--text3)", lineHeight: 1.5 }}>
                  Le numéro doit être enregistré chez <strong>{operator}</strong> en {country?.name}. Vérifiez bien avant d'envoyer.
                </span>
              </div>
            </div>
          </div>
        )}

        {/* STEP 2 — MONTANT */}
        {step === 2 && (
          <div className="fade-in">
            <div className="card">
              <div className="amount-display">
                <div className="amount-big">
                  <span className="amount-currency">€</span>
                  <span>{amount}</span>
                </div>
                <div className="amount-converted">
                  ≈ {received.toLocaleString()} {country?.currency} reçus
                </div>
                <div style={{ fontSize: 12, color: "var(--text3)", marginTop: 4 }}>
                  Taux : 1 EUR = {country?.rate} {country?.currency}
                </div>
              </div>
              <div className="numpad">
                {["1","2","3","4","5","6","7","8","9",".","0","⌫"].map(k => (
                  <button key={k} className={`num-btn ${k === "⌫" ? "del" : ""}`}
                    onClick={() => k === "⌫" ? numDel() : numPress(k)}>
                    {k}
                  </button>
                ))}
              </div>
              <div style={{ marginTop: 16 }}>
                <div className="fee-row"><span style={{ color: "var(--text3)" }}>Montant envoyé</span><span>{numAmt.toFixed(2)} €</span></div>
                <div className="fee-row"><span style={{ color: "var(--text3)" }}>Frais de transfert</span><span>{fee.toFixed(2)} €</span></div>
                <div className="fee-row"><span>Total débité</span><span style={{ color: "var(--primary)" }}>{total.toFixed(2)} €</span></div>
              </div>
              {numAmt < 5 && numAmt > 0 && (
                <div style={{ color: "var(--accent)", fontSize: 13, marginTop: 8, textAlign: "center" }}>Montant minimum : 5,00 €</div>
              )}
            </div>
          </div>
        )}

        {/* STEP 3 — RÉCAPITULATIF */}
        {step === 3 && (
          <div className="fade-in">
            <div className="card">
              <div style={{ textAlign: "center", marginBottom: 20 }}>
                <div style={{ fontSize: 32, marginBottom: 8 }}>{country?.flag}</div>
                <div style={{ fontFamily: "Sora", fontSize: 32, fontWeight: 700 }}>{numAmt.toFixed(2)} €</div>
                <div style={{ color: "var(--text3)", fontSize: 14 }}>vers {recipient}</div>
              </div>
              <div className="divider" />
              {[
                ["Destinataire", recipient],
                ["Téléphone", phone],
                ["Pays", `${country?.flag} ${country?.name}`],
                ["Opérateur", operator],
                ["Montant reçu", `${received.toLocaleString()} ${country?.currency}`],
                ["Frais", `${fee.toFixed(2)} €`],
                ["Total débité", `${total.toFixed(2)} €`],
              ].map(([l, v]) => (
                <div key={l} className="summary-row">
                  <div className="summary-label">{l}</div>
                  <div className="summary-value">{v}</div>
                </div>
              ))}
            </div>
            <div style={{ background: "var(--primary-light)", borderRadius: 14, padding: "12px 16px", display: "flex", gap: 10, marginBottom: 16 }}>
              <Icon name="shield" size={16} color="var(--primary)" />
              <span style={{ fontSize: 12, color: "var(--primary-dark)", lineHeight: 1.5 }}>
                Ce transfert est sécurisé et protégé. En cas de problème, notre support est disponible 24h/24.
              </span>
            </div>
          </div>
        )}

        <button
          className="btn-primary"
          disabled={!canNext[step]}
          onClick={() => step < 3 ? setStep(s => s + 1) : onSuccess({ country, operator, recipient, phone, amount: numAmt, received, currency: country?.currency, fee, total })}
        >
          {step < 3 ? "Continuer" : `Confirmer et envoyer ${total.toFixed(2)} €`}
        </button>
      </div>
    </div>
  );
}

