// ─── HISTORY SCREEN ───────────────────────────────────────────────────────────

function HistoryScreen() {
  const [filter, setFilter] = useState("Tout");
  const filters = ["Tout", "Complété", "En attente", "Congo", "Sénégal"];

  const filtered = MOCK_TRANSACTIONS.filter(tx => {
    if (filter === "Tout") return true;
    if (filter === "Complété") return tx.status === "completed";
    if (filter === "En attente") return tx.status === "pending";
    return tx.country === COUNTRIES.find(c => c.name.includes(filter))?.code;
  });

  return (
    <div className="screen fade-in">
      <div className="topbar">
        <div className="topbar-title">Historique</div>
      </div>
      <div className="filter-bar">
        {filters.map(f => (
          <button key={f} className={`filter-chip ${filter === f ? "active" : ""}`} onClick={() => setFilter(f)}>{f}</button>
        ))}
      </div>
      <div style={{ padding: "16px 20px 0" }}>
        <div style={{ fontSize: 12, color: "var(--text3)", marginBottom: 12, fontWeight: 600 }}>
          {filtered.length} transaction{filtered.length !== 1 ? "s" : ""}
        </div>
        {filtered.map(tx => <TxItem key={tx.id} tx={tx} />)}
        {filtered.length === 0 && (
          <div style={{ textAlign: "center", padding: "48px 0", color: "var(--text3)" }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>📭</div>
            <div style={{ fontWeight: 600 }}>Aucune transaction</div>
          </div>
        )}
      </div>
    </div>
  );
}

